preCopyScript.value:
@concat(
    'insert into target_schema.auditlog (processname, last_load_ts) values (''', item().processName, ''', (select max(load_ts) from ', item().sourceSchemaName, '.', item().tableName, '))'
)

expression.value:
@and(
    and(activity('metadata of population file').output.exists, equals(activity('metadata of population file').output.columnCount, 13)),
    greater(activity('metadata of population file').output.size, 0)
)
